import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(coord1, coord2, speed):
        return np.linalg.norm(coord1 - coord2) / speed

    def calculate_adjustment(current_truck_pos, all_truck_positions, target_pos):
        distances = [np.linalg.norm(target_pos - pos) for pos in all_truck_positions if not np.array_equal(pos, current_truck_pos)]
        if distances:
            return np.mean(distances)
        return 0

    best_node = None
    min_score = float('inf')

    for i, customer in enumerate(unvisited_customers):
        travel_t = travel_time(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_t
        window_start, window_end = time_windows[i]

        adjustment = calculate_adjustment(cur_truck_pos, all_truck_pos, customer)

        if arrival_time < window_start:
            wait_penalty = (window_start - arrival_time) ** 2  # penalizing earlier arrival more heavily
        else:
            wait_penalty = 0

        urgency = max(0, window_end - current_time)  # lesser value means more urgent
        score = travel_t + wait_penalty + urgency * 1.5 - adjustment  # Negative adjustment to prioritize closer distribution of tasks

        if score < min_score:
            min_score = score
            best_node = i

    return best_node
